"use strict";

const list = document.getElementById("shifts");
const empty = document.getElementById("empty");

let me = { id: "", displayName: "member", tag: "" };
riot.whoami().then((who) => { me = who; }).catch(() => {});

const names = new Map();

function render(rows) {
  rows.sort((a, b) => (a.value.starts_at || 0) - (b.value.starts_at || 0));
  empty.hidden = rows.length > 0;
  const pending = new Map();
  list.replaceChildren(...rows.map((row) => {
    const li = document.createElement("li");
    const label = document.createElement("span");
    label.className = "slot";
    label.textContent = row.value.label;
    const who = document.createElement("span");
    who.className = "who";
    const id = row.value.taken_by_id;
    if (typeof id === "string" && id) {
      who.textContent = names.get(id) || "";
      const waiting = pending.get(id);
      if (waiting) { waiting.push(who); } else { pending.set(id, [who]); }
    } else {
      who.textContent = "open";
    }
    const button = document.createElement("button");
    const mine = id === me.id;
    button.textContent = mine ? "Give it back" : "Take this shift";
    button.disabled = Boolean(id) && !mine;
    button.addEventListener("click", () => {
      riot.put(row.key, Object.assign({}, row.value, { taken_by_id: mine ? "" : me.id })).catch(() => {});
    });
    li.append(label, who, button);
    return li;
  }));
  pending.forEach((elements, id) => {
    riot.profile(id).then((profile) => {
      const text = profile.displayName + " \u00b7 " + profile.tag;
      names.set(id, text);
      elements.forEach((el) => { el.textContent = text; });
    }).catch(() => {});
  });
}

riot.watch("shifts", render);

:root { color-scheme: light dark; }
body { font: 16px/1.4 system-ui, sans-serif; margin: 16px; }
h1 { font-size: 20px; margin: 0 0 12px; }
ul { list-style: none; margin: 0; padding: 0; }
li { display: flex; align-items: center; gap: 8px; padding: 10px 0; border-bottom: 1px solid rgba(128, 128, 128, 0.35); }
.slot { flex: 1; }
.who { opacity: 0.7; font-size: 14px; }
button { font: inherit; padding: 6px 10px; }
